@persons.doc_type
class PersonIndex(DocType):
    id = fields.IntegerField()
    last_updated = fields.DateField()
    data = fields.ObjectField()

    employee_states = fields.ObjectField()
    external_states = fields.ObjectField()
    student_states = fields.ObjectField()
    addresses = fields.ObjectField()
    accounts = fields.ObjectField()
    functions = fields.ObjectField()
    degrees = fields.ObjectField()

    def __init__(self, *args, **kwargs):
        functions_list = ['employee_states', 'external_states', 'addresses',
                          'accounts','functions','degrees']

        # Generate the prepare_* functions
        for f in functions_list:
            _method = self.make_method(f, attrs[f])
            setattr(PersonIndex, "prepare_"+f, _method)

        super(PersonIndex, self).__init__(*args, **kwargs)

    def make_method(self, name, attrs):
        def _method(self, instance):
            objects_list = []

            for o in getattr(instance, name).all():
                d = {}
                for attr in attrs:
                    d[attr] = getattr(o,attr)

                for k in o.data.keys():
                    d[k] = o.data[k]

                objects_list.append(d)

            return objects_list
        return _method

    def prepare_data(self, instance):
        keys = Person.GOLDEN_RECORDS_FIELDS

        d = {}

        for k in keys:
            d[k] = instance.data.get(k, None)

        return d

    def get_instances_from_related(self, related_instance):
        return related_instance.person

    class Meta:
        model = Person
        related_models = [EmployeeState]

